DROP TABLE IF EXISTS `bookings`;
CREATE TABLE `bookings` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `userId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `packageId` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tourDate` datetime(3) DEFAULT NULL,
  `pax` int NOT NULL DEFAULT '1',
  `paymentType` enum('DP','HALF','FULL') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'FULL',
  `totalPrice` decimal(12,2) NOT NULL DEFAULT '0.00',
  `amountPaid` decimal(12,2) NOT NULL DEFAULT '0.00',
  `status` enum('PENDING','CONFIRMED','CANCELLED','COMPLETED') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `snapToken` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `bookings_userId_fkey` (`userId`),
  KEY `bookings_packageId_fkey` (`packageId`),
  CONSTRAINT `bookings_packageId_fkey` FOREIGN KEY (`packageId`) REFERENCES `tour_packages` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `bookings_userId_fkey` FOREIGN KEY (`userId`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

