  PRIMARY KEY (`id`),
  KEY `price_tiers_packageId_fkey` (`packageId`),
  CONSTRAINT `price_tiers_packageId_fkey` FOREIGN KEY (`packageId`) REFERENCES `tour_packages` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

