('250defdf-3998-48f8-8e9f-1b9202735be5',	'footer',	'{\"en\": {\"services\": [\"Domestic Tour\", \"International Tour\", \"Umrah\", \"Corporate Gathering\", \"Family Trip\", \"EduTrip & Academic Trip\"], \"brandDesc\": \"CV Titan Jaya Travelindo — Trusted tour & travel specialist in Palembang since 2013.\", \"copyright\": \"CV Titan Jaya Travelindo. All rights reserved.\", \"menuTitle\": \"Menu\", \"quickLinks\": [{\"href\": \"#beranda\", \"label\": \"Home\"}, {\"href\": \"#tentang\", \"label\": \"About Us\"}, {\"href\": \"#layanan\", \"label\": \"Services\"}, {\"href\": \"#paket\", \"label\": \"Tour Packages\"}, {\"href\": \"#galeri\", \"label\": \"Gallery\"}, {\"href\": \"#kontak\", \"label\": \"Contact\"}], \"contactTitle\": \"Contact\", \"servicesTitle\": \"Services\"}, \"id\": {\"services\": [\"Tur Domestik\", \"Tur Internasional\", \"Umroh\", \"Pertemuan Perusahaan\", \"Perjalanan Keluarga\", \"EduTrip & Perjalanan Akademik\"], \"brandDesc\": \"CV Titan Jaya Travelindo — Spesialis tour & travel terpercaya di Palembang sejak 2013.\", \"copyright\": \"CV Titan Jaya Travelindo. Semua hak dilindungi undang-undang.\", \"menuTitle\": \"Menu\", \"quickLinks\": [{\"href\": \"#beranda\", \"label\": \"Rumah\"}, {\"href\": \"#tentang\", \"label\": \"Tentang Kami\"}, {\"href\": \"#layanan\", \"label\": \"Layanan\"}, {\"href\": \"#paket\", \"label\": \"Paket Wisata\"}, {\"href\": \"#galeri\", \"label\": \"Galeri\"}, {\"href\": \"#kontak\", \"label\": \"Kontak\"}], \"contactTitle\": \"Kontak\", \"servicesTitle\": \"Layanan\"}, \"ms\": {\"services\": [\"Lawatan Dalam Negeri\", \"Lawatan Antarabangsa\", \"Umrah\", \"Perhimpunan Korporat\", \"Perjalanan Keluarga\", \"EduTrip & Perjalanan Akademik\"], \"brandDesc\": \"CV Titan Jaya Travelindo — Pakar pelancongan & pengembaraan yang dipercayai di Palembang sejak 2013.\", \"copyright\": \"CV Titan Jaya Travelindo. Semua hak terpelihara.\", \"menuTitle\": \"Menu\", \"quickLinks\": [{\"href\": \"#beranda\", \"label\": \"Rumah\"}, {\"href\": \"#tentang\", \"label\": \"Tentang Kami\"}, {\"href\": \"#layanan\", \"label\": \"Perkhidmatan\"}, {\"href\": \"#paket\", \"label\": \"Pakej Pelancongan\"}, {\"href\": \"#galeri\", \"label\": \"Galeri\"}, {\"href\": \"#kontak\", \"label\": \"Kenalan\"}], \"contactTitle\": \"Kenalan\", \"servicesTitle\": \"Perkhidmatan\"}}',	'2026-04-23 14:47:53.171',	'2026-04-23 16:39:48.876'),
('4e27838e-1817-4b65-96ab-18d0e1dbd7a0',	'navbar',	'{\"en\": {\"cta\": \"Book Now\", \"links\": [{\"href\": \"#beranda\", \"label\": \"Home\"}, {\"href\": \"#tentang\", \"label\": \"About\"}, {\"href\": \"#layanan\", \"label\": \"Services\"}, {\"href\": \"#paket\", \"label\": \"Tour Packages\"}, {\"href\": \"#galeri\", \"label\": \"Gallery\"}, {\"href\": \"#kontak\", \"label\": \"Contact\"}]}, \"id\": {\"cta\": \"Pesan Sekarang\", \"links\": [{\"href\": \"#beranda\", \"label\": \"Rumah\"}, {\"href\": \"#tentang\", \"label\": \"Tentang\"}, {\"href\": \"#layanan\", \"label\": \"Layanan\"}, {\"href\": \"#paket\", \"label\": \"Paket Wisata\"}, {\"href\": \"#galeri\", \"label\": \"Galeri\"}, {\"href\": \"#kontak\", \"label\": \"Kontak\"}]}, \"ms\": {\"cta\": \"Tempah Sekarang\", \"links\": [{\"href\": \"#beranda\", \"label\": \"Rumah\"}, {\"href\": \"#tentang\", \"label\": \"Tentang\"}, {\"href\": \"#layanan\", \"label\": \"Perkhidmatan\"}, {\"href\": \"#paket\", \"label\": \"Pakej Pelancongan\"}, {\"href\": \"#galeri\", \"label\": \"Galeri\"}, {\"href\": \"#kontak\", \"label\": \"Kenalan\"}]}}',	'2026-04-23 14:47:33.105',	'2026-04-23 16:39:34.352'),
('598fe897-c030-4e78-a653-a4e253359b0c',	'about',	'{\"en\": {\"badge\": \"About Us\", \"desc1\": \"Established in 2013 in Palembang, Titan Travel is a trusted travel partner for individuals and corporations. We have served thousands of customers with a wide range of domestic and international tour packages.\", \"desc2\": \"With more than a decade of experience and backed by a professional team, we are committed to delivering the best travel experiences. Follow us on\", \"desc3\": \"with\", \"desc4\": \"followers.\", \"title1\": \"CV Titan Jaya\", \"title2\": \"Travelindo\", \"yearsCard\": \"Years Serving Indonesian Travelers\", \"highlights\": [{\"desc\": \"Established since 2013 with thousands of satisfied customers\", \"title\": \"Trusted\"}, {\"desc\": \"Domestic & international tours around the world\", \"title\": \"Global Destinations\"}, {\"desc\": \"Personal service with a professional and experienced team\", \"title\": \"Prime Service\"}, {\"desc\": \"Best packages with competitive prices in their class\", \"title\": \"Competitive Pricing\"}]}, \"id\": {\"badge\": \"Tentang Kami\", \"desc1\": \"Didirikan pada tahun 2013 di Palembang, Titan Travel adalah mitra perjalanan terpercaya untuk individu dan perusahaan. Kami telah melayani ribuan pelanggan dengan berbagai macam paket wisata domestik dan internasional.\", \"desc2\": \"Dengan pengalaman lebih dari satu dekade dan didukung oleh tim profesional, kami berkomitmen untuk memberikan pengalaman perjalanan terbaik. Ikuti kami\", \"desc3\": \"dengan\", \"desc4\": \"pengikut.\", \"title1\": \"CV Titan Jaya\", \"title2\": \"Travelindo\", \"yearsCard\": \"Bertahun Melayani Wisatawan Indonesia\", \"highlights\": [{\"desc\": \"Berdiri sejak 2013 dengan ribuan pelanggan yang puas\", \"title\": \"Tepercaya\"}, {\"desc\": \"Tur domestik & internasional di seluruh dunia\", \"title\": \"Tujuan Global\"}, {\"desc\": \"Pelayanan personal dengan tim profesional dan berpengalaman\", \"title\": \"Layanan Perdana\"}, {\"desc\": \"Paket terbaik dengan harga bersaing di kelasnya\", \"title\": \"Harga Kompetitif\"}]}, \"ms\": {\"badge\": \"Tentang Kami\", \"desc1\": \"Ditubuhkan pada 2013 di Palembang, Titan Travel ialah rakan kongsi perjalanan yang dipercayai untuk individu dan syarikat. Kami telah melayani beribu-ribu pelanggan dengan pelbagai pakej pelancongan domestik dan antarabangsa.\", \"desc2\": \"Dengan lebih sedekad pengalaman dan disokong oleh pasukan profesional, kami komited untuk menyampaikan pengalaman perjalanan yang terbaik. Ikuti kami\", \"desc3\": \"dengan\", \"desc4\": \"pengikut.\", \"title1\": \"CV Titan Jaya\", \"title2\": \"Travelindo\", \"yearsCard\": \"Tahun Melayan Pengembara Indonesia\", \"highlights\": [{\"desc\": \"Ditubuhkan sejak 2013 dengan ribuan pelanggan yang berpuas hati\", \"title\": \"Dipercayai\"}, {\"desc\": \"Lawatan domestik & antarabangsa ke seluruh dunia\", \"title\": \"Destinasi Global\"}, {\"desc\": \"Perkhidmatan peribadi dengan pasukan profesional dan berpengalaman\", \"title\": \"Perkhidmatan Perdana\"}, {\"desc\": \"Pakej terbaik dengan harga yang kompetitif dalam kelas mereka\", \"title\": \"Harga Berdaya Saing\"}]}}',	'2026-04-23 14:47:37.055',	'2026-04-23 16:39:38.328'),
('8a59b796-0ef4-415e-9d1a-b938e2d13bf9',	'services',	'{\"en\": {\"badge\": \"Our Services\", \"items\": [{\"desc\": \"Complete Umrah packages with professional religious guidance & star hotels near the Grand Mosque.\", \"title\": \"Umrah\"}, {\"desc\": \"Explore the beauty of the Indonesian archipelago from Sabang to Merauke with complete packages.\", \"title\": \"Domestic Tour\"}, {\"desc\": \"Dream destinations in Asia, Europe, America, and around the world with the best itineraries.\", \"title\": \"International Tour\"}, {\"desc\": \"Well-organized and memorable employee gatherings, outings & team building events.\", \"title\": \"Corporate Gathering\"}, {\"desc\": \"A comfortable, safe, and memorable family vacation with your loved ones.\", \"title\": \"Family Trip\"}, {\"desc\": \"Educational visits for university and school students domestically and abroad at special prices.\", \"title\": \"EduTrip & Academic Trip\"}], \"title1\": \"Complete Travel\", \"title2\": \" Solutions\", \"readMore\": \"Learn More\", \"subtitle\": \"From Umrah to international tours, we provide integrated travel services for all your needs.\"}, \"id\": {\"badge\": \"Layanan kami\", \"items\": [{\"desc\": \"Paket umrah lengkap dengan bimbingan agama profesional & hotel berbintang dekat Masjidil Haram.\", \"title\": \"Umroh\"}, {\"desc\": \"Jelajahi keindahan kepulauan Indonesia dari Sabang hingga Merauke dengan paket lengkap.\", \"title\": \"Tur Domestik\"}, {\"desc\": \"Destinasi impian di Asia, Eropa, Amerika, dan seluruh dunia dengan itinerary terbaik.\", \"title\": \"Tur Internasional\"}, {\"desc\": \"Pertemuan karyawan, tamasya & acara membangun tim yang terorganisir dengan baik dan berkesan.\", \"title\": \"Pertemuan Perusahaan\"}, {\"desc\": \"Liburan keluarga yang nyaman, aman, dan berkesan bersama orang tercinta.\", \"title\": \"Perjalanan Keluarga\"}, {\"desc\": \"Kunjungan edukasi bagi mahasiswa dan pelajar dalam dan luar negeri dengan harga khusus.\", \"title\": \"EduTrip & Perjalanan Akademik\"}], \"title1\": \"Perjalanan Lengkap\", \"title2\": \"Solusi\", \"readMore\": \"Pelajari Lebih Lanjut\", \"subtitle\": \"Dari umrah hingga tur internasional, kami menyediakan layanan perjalanan terpadu untuk segala kebutuhan Anda.\"}, \"ms\": {\"badge\": \"Perkhidmatan Kami\", \"items\": [{\"desc\": \"Pakej umrah lengkap dengan bimbingan agama profesional & hotel berbintang berhampiran Masjidil Haram.\", \"title\": \"Umrah\"}, {\"desc\": \"Terokai keindahan kepulauan Indonesia dari Sabang hingga Merauke dengan pakej lengkap.\", \"title\": \"Lawatan Dalam Negeri\"}, {\"desc\": \"Destinasi impian di Asia, Eropah, Amerika dan seluruh dunia dengan jadual perjalanan terbaik.\", \"title\": \"Lawatan Antarabangsa\"}, {\"desc\": \"Perhimpunan pekerja yang teratur dan tidak dapat dilupakan, acara persiaran & pembinaan pasukan.\", \"title\": \"Perhimpunan Korporat\"}, {\"desc\": \"Percutian keluarga yang selesa, selamat dan tidak dapat dilupakan bersama orang tersayang.\", \"title\": \"Perjalanan Keluarga\"}, {\"desc\": \"Lawatan pendidikan untuk pelajar universiti dan sekolah di dalam dan luar negara dengan harga istimewa.\", \"title\": \"EduTrip & Perjalanan Akademik\"}], \"title1\": \"Perjalanan Lengkap\", \"title2\": \"Penyelesaian\", \"readMore\": \"Ketahui Lebih Lanjut\", \"subtitle\": \"Dari Umrah ke pelancongan antarabangsa, kami menyediakan perkhidmatan pelancongan bersepadu untuk semua keperluan anda.\"}}',	'2026-04-23 14:47:39.277',	'2026-04-23 16:39:39.711'),
('ba2b4480-9a68-40c0-9486-92ed6c4eb765',	'gallery',	'{\"en\": {\"badge\": \"Gallery\", \"items\": [{\"title\": \"Bali, Indonesia\", \"category\": \"Domestic\"}, {\"title\": \"Tokyo, Japan\", \"category\": \"International\"}, {\"title\": \"Raja Ampat, Papua\", \"category\": \"Domestic\"}, {\"title\": \"Dubai, UAE\", \"category\": \"International\"}, {\"title\": \"Labuan Bajo, NTT\", \"category\": \"Domestic\"}, {\"title\": \"Santorini, Greece\", \"category\": \"International\"}, {\"title\": \"Bangkok, Thailand\", \"category\": \"International\"}, {\"title\": \"Lombok, NTB\", \"category\": \"Domestic\"}], \"title1\": \"Precious\", \"title2\": \"Moments\", \"subtitle\": \"A documentation of trips and tourist destinations we have visited.\"}, \"id\": {\"badge\": \"Galeri\", \"items\": [{\"title\": \"Bali, Indonesia\", \"category\": \"Domestik\"}, {\"title\": \"Tokyo, Jepang\", \"category\": \"Internasional\"}, {\"title\": \"Raja Ampat, Papua\", \"category\": \"Domestik\"}, {\"title\": \"Dubai, UEA\", \"category\": \"Internasional\"}, {\"title\": \"Labuan Bajo, NTT\", \"category\": \"Domestik\"}, {\"title\": \"Santorini, Yunani\", \"category\": \"Internasional\"}, {\"title\": \"Bangkok, Thailand\", \"category\": \"Internasional\"}, {\"title\": \"Lombok, NTB\", \"category\": \"Domestik\"}], \"title1\": \"Berharga\", \"title2\": \"Momen\", \"subtitle\": \"Dokumentasi perjalanan dan destinasi wisata yang pernah kami kunjungi.\"}, \"ms\": {\"badge\": \"Galeri\", \"items\": [{\"title\": \"Bali, Indonesia\", \"category\": \"Dalam negeri\"}, {\"title\": \"Tokyo, Jepun\", \"category\": \"antarabangsa\"}, {\"title\": \"Raja Ampat, Papua\", \"category\": \"Dalam negeri\"}, {\"title\": \"Dubai, UAE\", \"category\": \"antarabangsa\"}, {\"title\": \"Labuan Bajo, NTT\", \"category\": \"Dalam negeri\"}, {\"title\": \"Santorini, Greece\", \"category\": \"antarabangsa\"}, {\"title\": \"Bangkok, Thailand\", \"category\": \"antarabangsa\"}, {\"title\": \"Lombok, NTB\", \"category\": \"Dalam negeri\"}], \"title1\": \"berharga\", \"title2\": \"Detik-detik\", \"subtitle\": \"Dokumentasi perjalanan dan destinasi pelancongan yang telah kami lawati.\"}}',	'2026-04-23 14:47:46.638',	'2026-04-23 16:39:44.746'),
('c9eb7b57-acde-493b-b79a-5fa72450e756',	'packages',	'{\"en\": {\"badge\": \"Tour Packages\", \"items\": [{\"tag\": \"Best Seller\", \"title\": \"The Wonder of Raja Ampat\", \"capacity\": \"Max 15 pax\", \"duration\": \"5 Days 4 Nights\", \"location\": \"West Papua\"}, {\"tag\": \"Popular\", \"title\": \"Explore Bali Paradise\", \"capacity\": \"Max 20 pax\", \"duration\": \"4 Days 3 Nights\", \"location\": \"Bali, Indonesia\"}, {\"tag\": \"International\", \"title\": \"Tokyo & Osaka Adventure\", \"capacity\": \"Max 20 pax\", \"duration\": \"7 Days 6 Nights\", \"location\": \"Japan\"}, {\"tag\": \"Adventure\", \"title\": \"Labuan Bajo & Komodo\", \"capacity\": \"Max 12 pax\", \"duration\": \"4 Days 3 Nights\", \"location\": \"NTT, Indonesia\"}, {\"tag\": \"Honeymoon\", \"title\": \"Maldives Honeymoon\", \"capacity\": \"Max 2 pax\", \"duration\": \"5 Days 4 Nights\", \"location\": \"Maldives\"}, {\"tag\": \"Umrah\", \"title\": \"Regular Plus Umrah\", \"capacity\": \"Max 45 pax\", \"duration\": \"9 Days 8 Nights\", \"location\": \"Makkah & Madinah\"}], \"detail\": \"Details\", \"title1\": \"Popular\", \"title2\": \"Destinations\", \"viewAll\": \"View All Packages\", \"subtitle\": \"The best tour packages at competitive prices with complete facilities.\"}, \"id\": {\"badge\": \"Paket Wisata\", \"items\": [{\"tag\": \"Penjual Terbaik\", \"title\": \"Keajaiban Raja Ampat\", \"capacity\": \"Maks 15 orang\", \"duration\": \"5 Hari 4 Malam\", \"location\": \"Papua Barat\"}, {\"tag\": \"Populer\", \"title\": \"Jelajahi Surga Bali\", \"capacity\": \"Maks 20 orang\", \"duration\": \"4 Hari 3 Malam\", \"location\": \"Bali, Indonesia\"}, {\"tag\": \"Internasional\", \"title\": \"Petualangan Tokyo & Osaka\", \"capacity\": \"Maks 20 orang\", \"duration\": \"7 Hari 6 Malam\", \"location\": \"Jepang\"}, {\"tag\": \"Petualangan\", \"title\": \"Labuan Bajo & Komodo\", \"capacity\": \"Maks 12 orang\", \"duration\": \"4 Hari 3 Malam\", \"location\": \"NTT, Indonesia\"}, {\"tag\": \"Bulan madu\", \"title\": \"Bulan Madu Maladewa\", \"capacity\": \"Maks 2 orang\", \"duration\": \"5 Hari 4 Malam\", \"location\": \"Maladewa\"}, {\"tag\": \"Umroh\", \"title\": \"Reguler Ditambah Umrah\", \"capacity\": \"Maks 45 orang\", \"duration\": \"9 Hari 8 Malam\", \"location\": \"Makkah & Madinah\"}], \"detail\": \"Detail\", \"title1\": \"Populer\", \"title2\": \"Tujuan\", \"viewAll\": \"Lihat Semua Paket\", \"subtitle\": \"Paket wisata terbaik dengan harga bersaing dengan fasilitas lengkap.\"}, \"ms\": {\"badge\": \"Pakej Pelancongan\", \"items\": [{\"tag\": \"Best Seller\", \"title\": \"Keajaiban Raja Ampat\", \"capacity\": \"Max 15 pax\", \"duration\": \"5 Hari 4 Malam\", \"location\": \"Papua Barat\"}, {\"tag\": \"Popular\", \"title\": \"Terokai Bali Paradise\", \"capacity\": \"Max 20 pax\", \"duration\": \"4 Hari 3 Malam\", \"location\": \"Bali, Indonesia\"}, {\"tag\": \"antarabangsa\", \"title\": \"Pengembaraan Tokyo & Osaka\", \"capacity\": \"Max 20 pax\", \"duration\": \"7 Hari 6 Malam\", \"location\": \"Jepun\"}, {\"tag\": \"Pengembaraan\", \"title\": \"Labuan Bajo & Komodo\", \"capacity\": \"Max 12 pax\", \"duration\": \"4 Hari 3 Malam\", \"location\": \"NTT, Indonesia\"}, {\"tag\": \"berbulan madu\", \"title\": \"Bulan Madu Maldives\", \"capacity\": \"Max 2 pax\", \"duration\": \"5 Hari 4 Malam\", \"location\": \"Maldives\"}, {\"tag\": \"Umrah\", \"title\": \"Umrah Plus Biasa\", \"capacity\": \"Maksimum 45 pax\", \"duration\": \"9 Hari 8 Malam\", \"location\": \"Makkah & Madinah\"}], \"detail\": \"Butiran\", \"title1\": \"Popular\", \"title2\": \"Destinasi\", \"viewAll\": \"Lihat Semua Pakej\", \"subtitle\": \"Pakej pelancongan terbaik dengan harga yang kompetitif dengan kemudahan yang lengkap.\"}}',	'2026-04-23 14:47:42.906',	'2026-04-23 16:39:42.061'),
('f1e061db-b005-4bde-9802-0190027312fd',	'testimonials',	'{\"en\": {\"badge\": \"Testimonials\", \"items\": [{\"name\": \"Rina Sari\", \"role\": \"Family Trip Bali\", \"text\": \"An amazing family vacation experience! Everything was beautifully arranged by the Titan Travel team. Great hotel, comfortable transport, and a very friendly guide.\", \"avatar\": \"RS\", \"rating\": 5}, {\"name\": \"Ahmad Fadli\", \"role\": \"Corporate Gathering\", \"text\": \"Our company has used Titan Travel 3 times for employee gatherings. Always satisfying! The team is professional and very cooperative.\", \"avatar\": \"AF\", \"rating\": 5}, {\"name\": \"Dewi Anggraini\", \"role\": \"Umrah Regular\", \"text\": \"Alhamdulillah, I was able to perform Umrah with Titan Travel. The service from start to finish was excellent. Hotel near the Grand Mosque, clear religious guidance.\", \"avatar\": \"DA\", \"rating\": 5}, {\"name\": \"Budi Santoso\", \"role\": \"Japan Tour\", \"text\": \"The Japan tour with Titan Travel was so much fun! The itinerary was complete, from Tokyo to Osaka. Worth every penny!\", \"avatar\": \"BS\", \"rating\": 5}, {\"name\": \"Siti Nurhaliza\", \"role\": \"Student EduTrip\", \"text\": \"Our campus field trip was handled by Titan Travel very professionally. Students were happy and the activities ran smoothly. Thank you Titan Travel!\", \"avatar\": \"SN\", \"rating\": 5}, {\"name\": \"Hendra Wijaya\", \"role\": \"Raja Ampat Tour\", \"text\": \"Raja Ampat is beautiful, but the experience was even more perfect because Titan Travel handled everything. Snorkeling, diving, sunset — all amazing!\", \"avatar\": \"HW\", \"rating\": 5}], \"title1\": \"What Our\", \"title2\": \"Customers Say\", \"subtitle\": \"Thousands of customers have trusted Titan Travel with their journeys.\"}, \"id\": {\"badge\": \"Testimonial\", \"items\": [{\"name\": \"Rina Sari\", \"role\": \"Perjalanan Keluarga Bali\", \"text\": \"Pengalaman liburan keluarga yang luar biasa! Semuanya diatur dengan indah oleh tim Titan Travel. Hotel yang bagus, transportasi yang nyaman, dan pemandu yang sangat ramah.\", \"avatar\": \"RS\", \"rating\": 5}, {\"name\": \"Ahmad Fadli\", \"role\": \"Pertemuan Perusahaan\", \"text\": \"Perusahaan kami telah menggunakan Titan Travel 3 kali untuk pertemuan karyawan. Selalu memuaskan! Timnya profesional dan sangat kooperatif.\", \"avatar\": \"AF\", \"rating\": 5}, {\"name\": \"Dewi Anggraini\", \"role\": \"Umroh Reguler\", \"text\": \"Alhamdulillah bisa menunaikan umrah bersama Titan Travel. Layanan dari awal hingga akhir sangat baik. Hotel dekat Masjidil Haram, tuntunan agama jelas.\", \"avatar\": \"DA\", \"rating\": 5}, {\"name\": \"Budi Santoso\", \"role\": \"Tur Jepang\", \"text\": \"Tur Jepang bersama Titan Travel sangat menyenangkan! Itinerarynya pun lengkap, dari Tokyo ke Osaka. Bernilai setiap sen!\", \"avatar\": \"BS\", \"rating\": 5}, {\"name\": \"Siti Nurhaliza\", \"role\": \"Perjalanan Edu Pelajar\", \"text\": \"Kunjungan lapangan kampus kami ditangani oleh Titan Travel dengan sangat profesional. Siswa senang dan kegiatan berjalan lancar. Terima kasih Titan Perjalanan!\", \"avatar\": \"hal\", \"rating\": 5}, {\"name\": \"Hendra Wijaya\", \"role\": \"Wisata Raja Ampat\", \"text\": \"Raja Ampat memang indah, namun pengalamannya menjadi lebih sempurna karena Titan Travel menangani semuanya. Snorkeling, menyelam, matahari terbenam — semuanya menakjubkan!\", \"avatar\": \"HW\", \"rating\": 5}], \"title1\": \"Apa yang kita\", \"title2\": \"Kata Pelanggan\", \"subtitle\": \"Ribuan pelanggan telah mempercayai Titan Travel dalam perjalanan mereka.\"}, \"ms\": {\"badge\": \"Testimoni\", \"items\": [{\"name\": \"Rina Sari\", \"role\": \"Family Trip Bali\", \"text\": \"Pengalaman percutian keluarga yang menakjubkan! Segala-galanya telah diatur dengan indah oleh pasukan Titan Travel. Hotel yang hebat, pengangkutan yang selesa, dan pemandu yang sangat mesra.\", \"avatar\": \"RS\", \"rating\": 5}, {\"name\": \"Ahmad Fadli\", \"role\": \"Perhimpunan Korporat\", \"text\": \"Syarikat kami telah menggunakan Titan Travel sebanyak 3 kali untuk perjumpaan pekerja. Sentiasa memuaskan! Pasukan ini profesional dan sangat bekerjasama.\", \"avatar\": \"AF\", \"rating\": 5}, {\"name\": \"Dewi Anggraini\", \"role\": \"Umrah Biasa\", \"text\": \"Alhamdulillah dapat menunaikan umrah bersama Titan Travel. Perkhidmatan dari awal hingga akhir adalah sangat baik. Hotel berhampiran Masjidil Haram, bimbingan agama yang jelas.\", \"avatar\": \"DA\", \"rating\": 5}, {\"name\": \"Budi Santoso\", \"role\": \"Jelajah Jepun\", \"text\": \"Lawatan Jepun dengan Titan Travel sangat menyeronokkan! Jadual perjalanan telah lengkap, dari Tokyo ke Osaka. Berbaloi setiap sen!\", \"avatar\": \"BS\", \"rating\": 5}, {\"name\": \"Siti Nurhaliza\", \"role\": \"Pelajar EduTrip\", \"text\": \"Lawatan lapangan kampus kami dikendalikan oleh Titan Travel dengan sangat profesional. Murid-murid gembira dan aktiviti berjalan dengan lancar. Terima kasih Titan Travel!\", \"avatar\": \"SN\", \"rating\": 5}, {\"name\": \"Hendra Wijaya\", \"role\": \"Jelajah Raja Ampat\", \"text\": \"Raja Ampat memang cantik, tetapi pengalaman itu lebih sempurna kerana Titan Travel mengendalikan segala-galanya. Snorkeling, menyelam, matahari terbenam — semuanya menakjubkan!\", \"avatar\": \"HW\", \"rating\": 5}], \"title1\": \"Apa Kami\", \"title2\": \"Kata Pelanggan\", \"subtitle\": \"Beribu-ribu pelanggan telah mempercayai Titan Travel dengan perjalanan mereka.\"}}',	'2026-04-23 14:47:45.249',	'2026-04-23 16:39:43.775'),
('f9807e74-b455-4af1-ba75-20c7857fc4fe',	'hero',	'{\"en\": {\"cta1\": \"View Tour Packages\", \"cta2\": \"Contact Us\", \"badge\": \"Trusted Since 2013\", \"stats\": [{\"label\": \"Years Experience\", \"value\": \"10+\"}, {\"label\": \"Followers\", \"value\": \"32K+\"}, {\"label\": \"Trips Done\", \"value\": \"500+\"}, {\"label\": \"Google Rating\", \"value\": \"4.8\"}], \"title1\": \"Explore the World\", \"title2\": \"With Titan Travel\", \"subtitle\": \"Umrah Specialist, Corporate Gathering, Family Trip, Domestic & International Tours. Trust us with your best journey.\"}, \"id\": {\"cta1\": \"Lihat Paket Wisata\", \"cta2\": \"Hubungi kami\", \"badge\": \"Terpercaya Sejak 2013\", \"stats\": [{\"label\": \"Pengalaman Bertahun-tahun\", \"value\": \"10+\"}, {\"label\": \"Pengikut\", \"value\": \"32K+\"}, {\"label\": \"Perjalanan Selesai\", \"value\": \"500+\"}, {\"label\": \"Peringkat Google\", \"value\": \"4.8\"}], \"title1\": \"Jelajahi Dunia\", \"title2\": \"Dengan Perjalanan Titan\", \"subtitle\": \"Spesialis Umroh, Corporate Gathering, Family Trip, Tour Domestik & Internasional. Percayakan perjalanan terbaik Anda kepada kami.\"}, \"ms\": {\"cta1\": \"Lihat Pakej Pelancongan\", \"cta2\": \"Hubungi Kami\", \"badge\": \"Dipercayai Sejak 2013\", \"stats\": [{\"label\": \"Pengalaman Tahun\", \"value\": \"10+\"}, {\"label\": \"Pengikut\", \"value\": \"32K+\"}, {\"label\": \"Perjalanan Selesai\", \"value\": \"500+\"}, {\"label\": \"Penilaian Google\", \"value\": \"4.8\"}], \"title1\": \"Terokai Dunia\", \"title2\": \"Dengan Titan Travel\", \"subtitle\": \"Pakar Umrah, Perhimpunan Korporat, Lawatan Keluarga, Lawatan Domestik & Antarabangsa. Percayai kami dengan perjalanan terbaik anda.\"}}',	'2026-04-23 14:47:35.003',	'2026-04-23 16:39:36.218');

DROP TABLE IF EXISTS `testimonials`;
CREATE TABLE `testimonials` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `role` json DEFAULT NULL,
  `text` json NOT NULL,
  `avatar` text COLLATE utf8mb4_unicode_ci,
  `rating` int NOT NULL DEFAULT '5',
  `isPublished` tinyint(1) NOT NULL DEFAULT '0',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `testimonials` (`id`, `name`, `role`, `text`, `avatar`, `rating`, `isPublished`, `createdAt`, `updatedAt`) VALUES
('327213ee-5e0a-4301-bf47-bf190452d42a',	'Jasurjon',	'{\"en\": \"Backpacker\", \"id\": \"Backpacker\", \"ms\": \"Backpacker\"}',	'{\"en\": \"Aplikasi ini sangat membantu saya dalam memilih paket wisata paling murah tapi durasinya mantap!\", \"id\": \"Aplikasi ini sangat membantu saya dalam memilih paket wisata paling murah tapi durasinya mantap!\", \"ms\": \"Aplikasi ini sangat membantu saya dalam memilih pakej wisata paling murah tetapi durasinya mantap!\"}',	'https://i.pravatar.cc/150?u=Jasurjon',	5,	1,	'2026-04-23 16:39:52.835',	'2026-04-23 16:39:52.835'),
('c53557b0-f4d5-4119-b671-7c791014576e',	'Siti Rahayu',	'{\"en\": \"Family Traveler\", \"id\": \"Wisatawan Keluarga\", \"ms\": \"Pengembara Keluarga\"}',	'{\"en\": \"Rekomendasi TOPSIS-nya akurat. Saya pilih paket Bali dan sangat puas dengan fasilitasnya.\", \"id\": \"Rekomendasi TOPSIS-nya akurat. Saya pilih paket Bali dan sangat puas dengan fasilitasnya.\", \"ms\": \"Rekomendasi TOPSIS-nya akurat. Saya pilih pakej Bali dan sangat puas dengan kemudahannya.\"}',	'https://i.pravatar.cc/150?u=Siti Rahayu',	5,	1,	'2026-04-23 16:39:53.230',	'2026-04-23 16:39:53.230');

