DROP TABLE IF EXISTS `tour_packages`;
CREATE TABLE `tour_packages` (
  `id` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` json NOT NULL,
  `description` json DEFAULT NULL,
  `location` json NOT NULL,
  `duration` json NOT NULL,
  `images` json NOT NULL,
  `facilityScore` int NOT NULL DEFAULT '3',
  `departureScore` int NOT NULL DEFAULT '1',
  `durationDays` int NOT NULL DEFAULT '1',
  `rating` double NOT NULL DEFAULT '0',
  `reviews` int NOT NULL DEFAULT '0',
  `isPublished` tinyint(1) NOT NULL DEFAULT '0',
  `createdAt` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updatedAt` datetime(3) NOT NULL,
  `capacity` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `tour_packages_slug_key` (`slug`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `tour_packages` (`id`, `slug`, `title`, `description`, `location`, `duration`, `images`, `facilityScore`, `departureScore`, `durationDays`, `rating`, `reviews`, `isPublished`, `createdAt`, `updatedAt`, `capacity`) VALUES
